inline void SurroundWithQuotes (CString& rString)
/*
	Effect:		Set rString to be the contents of rString within quotes.
				Obviously, this could have been done without a separate 
				function, but it makes the calling code easier to read.
*/
{
	rString = "\"" + rString + "\"";
}

