BOOL CProgramManagerClient::CreateGroup (LPCTSTR lpszGroupName, LPCTSTR lpszGroupFile /*= NULL*/)
{
	DWORD			dwReturn;

	Connect ();	
	if (lpszGroupFile != NULL)
		dwReturn = (DWORD) Command (szCreateGroupFile, lpszGroupName, lpszGroupFile);
	else
		dwReturn = (DWORD) Command (szCreateGroup, lpszGroupName);	
		
	return (dwReturn != FALSE);	
}	
	

