BOOL CProgramManagerClient::AddItem (LPCTSTR lpszCommandLine, 
										   LPCTSTR lpszDescription,
										   LPCTSTR lpszIconPath /*= NULL*/,
										   UINT nIcon /*= 0*/,
										   int xPos /*= -1*/,
										   int yPos /*= -1*/,
										   LPCTSTR lpszDefaultDirectory /*= NULL*/,
										   int nHotKey /*= -1*/,
										   BOOL bMinimize /*= 0*/)
{
	_TCHAR	szHotKey [10];
	DWORD	dwReturn;

	ASSERT (lpszCommandLine);
	ASSERT (lpszDescription);
	
	if (nHotKey == -1)
		szHotKey[0] = '\0';
	else
		_itoa (nHotKey, szHotKey, 10);
	
	Connect ();
	dwReturn = (DWORD) Command (szAddItem, lpszCommandLine,
								lpszDescription, 
								(lpszIconPath == NULL) ? lpszCommandLine : lpszIconPath,
								nIcon, xPos, yPos, 
								(lpszDefaultDirectory == NULL) ? _T("") : lpszDefaultDirectory,
								szHotKey,
								(bMinimize == 0) ? 0 : 1);
	return (dwReturn != FALSE);	
}

										   
BOOL CProgramManagerClient::FillListBox (CListBox* pListBox)
{
	CString		Groups;
	LPTSTR		lpszGroups;
	LPCTSTR		lpszGroup;

	ASSERT (pListBox);
				
	Connect ();                         
	Request (szProgramManagerGroupItem, Groups);
	lpszGroups = strdup (Groups);
	lpszGroup = strtok (lpszGroups, _T("\r\n"));
	
	while (lpszGroup)
	{
		pListBox->AddString (lpszGroup);		
		lpszGroup = strtok (NULL, _T("\r\n"));
	}

	free (lpszGroups);						
	return TRUE;
}


BOOL CProgramManagerClient::Connect (BOOL bStartIfNeeded /*= TRUE*/)
/*
	Effect:		Start a DDE Client with the program manager. If progman
				is not running, and bStartIfNeeded is nonnull, attempt to
				launch it.
*/				
{
	if (m_bConnected)
		return TRUE;
		
	if (CDDEClient::Connect (szProgramManagerTopic, szProgramManagerTopic))
	{
		m_bConnected = TRUE;
		return TRUE;
	}
	else if (bStartIfNeeded)
	{
		LPSTR aszProgman = AllocANSIFromUnicode(szProgman);
		WinExec (aszProgman, SW_SHOW);
		FreeANSI(aszProgman);

		return Connect (FALSE);
	}
	else
		return FALSE;
}

BOOL CProgramManagerClient::Disconnect ()
{
	BOOL		bSuccess;
	
	if (!m_bConnected)
		return TRUE;
		
	bSuccess = CDDEClient::Disconnect ();
	if (bSuccess)
		m_bConnected = FALSE;
		
	return bSuccess;	
}
		
