// virtual 
BOOL CProgramManagerClient::CreateProgramItem (LPCTSTR lpszGroupName,
											   LPCTSTR lpszProgramPath,
											   LPCTSTR lpszArguments,
											   LPCTSTR lpszCaption,
											   LPCTSTR lpszIconPath /*= NULL*/,
											   UINT nIcon /*= 0*/,
											   int nHotKey /*= -1*/,
											   int nCmdShow /*= SW_SHOW*/)
{
	Connect ();
	CreateGroup (lpszGroupName);
	ReplaceItem (lpszCaption);

	CString	CommandLine = lpszProgramPath;
	if (CommandLine.FindOneOf (_T(" \t")) != -1)
		SurroundWithQuotes (CommandLine);

	if (lpszArguments != NULL)
	{
		CommandLine += _T(" ");
		CommandLine += lpszArguments;
	}

	BOOL	bMinimized = (nCmdShow == SW_MINIMIZE) ||
						 (nCmdShow == SW_SHOWMINIMIZED);

	return AddItem (CommandLine,
					lpszCaption,
					lpszIconPath,
					nIcon,
					nHotKey,
					bMinimized);
}


// virtual 
BOOL CProgramManagerClient::RemoveProgramItem (LPCTSTR lpszGroupName,
						LPCTSTR lpszCaption)
{
	Connect();
	CreateGroup(lpszGroupName);	 // really
	return DeleteItem (lpszCaption);
}


// virtual 
BOOL CProgramManagerClient::RemoveProgramGroup (LPCTSTR lpszGroupName,
						 BOOL bRemoveIfNotEmpty /*= FALSE*/)
{
	return DeleteGroup (lpszGroupName);
}
